// Parse any passage name like "Genesis 1", "1 Corinthians 13", "Song of Solomon 4" into {book, ch}
const parsePassage=(pName)=>{
  const m=pName.match(/^(.+?)\s+(\d+)$/);
  if(!m)return null;
  return{book:m[1],ch:parseInt(m[2],10)};
};
